#!/bin/bash # ============================================================================= # Foreign Trade Prospecting Skill — One-Click Installer # Supports: Linux / macOS / Windows (Git Bash / WSL) # Version: 2.0 # ============================================================================= set -euo pipefail  RED="\033[31m"; GREEN="\033[32m"; YELLOW="\033[33m"; CYAN="\033[36m"; NC="\033[0m" ok()  { echo -e "${GREEN}[OK]${NC} $1"; } warn(){ echo -e "${YELLOW}[WARN]${NC} $1"; } err() { echo -e "${RED}[ERR]${NC} $1"; } info(){ echo -e "${CYAN}[INFO]${NC} $1"; }  SKILL_DIR="$(cd "$(dirname "$0")/.." && pwd)" echo "" echo "========================================" echo "  Foreign Trade Prospecting Installer" echo "  v2.0 — One-Click Setup" echo "========================================" echo "" info "Skill directory: $SKILL_DIR"  # ====== Step 1: Detect OS ====== echo "[1/7] Detecting OS..." case "$(uname -s)" in     Linux*)   OS=linux;;     Darwin*)  OS=macos;;     CYGWIN*|MINGW*|MSYS*) OS=windows;;     *)        OS=unknown;; esac ok "OS: $OS"  # ====== Step 2: Check Node.js ====== echo "[2/7] Checking Node.js..." if ! command -v node &>/dev/null; then     err "Node.js not found. Install Node.js >=18: https://nodejs.org/"     exit 1 fi NODE_MAJOR=$(node -v | cut -d'v' -f2 | cut -d'.' -f1) if [ "$NODE_MAJOR" -lt 18 ]; then     err "Node.js $(node -v) is too old. Need >=18."     exit 1 fi ok "Node.js $(node -v)"  # ====== Step 3: Check Python ====== echo "[3/7] Checking Python..." PYTHON="" for py in python3 python; do     if command -v "$py" &>/dev/null; then         PYVER=$("$py" --version 2>&1 | grep -oP '3\.\d+')         if [ -n "$PYVER" ]; then             PYTHON="$py"             break         fi     fi done if [ -z "$PYTHON" ]; then     warn "Python 3 not found. Config generation will be skipped."     warn "Install Python: https://python.org/downloads/" else     ok "Python: $($PYTHON --version 2>&1)" fi  # ====== Step 4: Check / Install Docker + Reacher ====== echo "[4/7] Setting up Docker + email verifier..." if ! command -v docker &>/dev/null; then     warn "Docker not found."     if [ "$OS" = "macos" ]; then         warn "  Install: https://docs.docker.com/desktop/install/mac-install/"     elif [ "$OS" = "windows" ]; then         warn "  Install Docker Desktop: https://docs.docker.com/desktop/install/windows-install/"     else         warn "  Install: https://docs.docker.com/engine/install/"     fi     warn "  Email verification via Docker will be unavailable until Docker is installed." else     ok "Docker $(docker --version | head -1)"     # Pull & start Reacher     if docker ps --format '{{.Names}}' 2>/dev/null | grep -q '^reacher$'; then         info "Reacher already running. Restarting..."         docker rm -f reacher 2>/dev/null || true     fi     info "Pulling reacherhq/backend:latest..."     docker pull reacherhq/backend:latest 2>&1 | tail -1     docker run -d --name reacher -p 8080:8080 --restart unless-stopped \         reacherhq/backend:latest 2>/dev/null     # Verify it started     sleep 2     if curl -s http://localhost:8080/health > /dev/null 2>&1; then         ok "Reacher running on http://localhost:8080"     else         warn "Reacher may not have started. Check: docker logs reacher"     fi fi  # ====== Step 5: Install Prospector MCP ====== echo "[5/7] Installing Prospector MCP (free: 50/day)..." if npm install -g prospector-mcp 2>/dev/null; then     ok "Prospector MCP installed globally" else     warn "Global install failed. You can still use: npx prospector-mcp" fi  # ====== Step 6: Clone & Build mcp-whatsapp ====== echo "[6/7] Setting up mcp-whatsapp..." WHATSAPP_DIR="${HOME}/mcp-whatsapp" if [ -d "$WHATSAPP_DIR" ]; then     ok "mcp-whatsapp already exists at $WHATSAPP_DIR" else     if command -v git &>/dev/null; then         info "Cloning mcp-whatsapp..."         git clone https://github.com/Sealjay/mcp-whatsapp.git "$WHATSAPP_DIR" 2>&1 | tail -1         cd "$WHATSAPP_DIR"         if [ -f "Makefile" ]; then             make build 2>&1 | tail -3 && ok "mcp-whatsapp built" || warn "Build failed. Try: cd $WHATSAPP_DIR && make build"         elif [ -f "go.mod" ]; then             go build -o bin/whatsapp-mcp ./cmd/... 2>&1 && ok "mcp-whatsapp built" || warn "Build failed. Need Go installed."         fi         cd "$SKILL_DIR"     else         warn "git not found. Please manually clone:"         warn "  git clone https://github.com/Sealjay/mcp-whatsapp.git ~/mcp-whatsapp"         warn "  cd ~/mcp-whatsapp && make build"     fi fi  # ====== Step 7: Generate MCP Config ====== echo "[7/7] Generating MCP config..." if [ -n "$PYTHON" ]; then     "$PYTHON" "${SKILL_DIR}/scripts/generate_config.py" && \         ok "MCP config generated" || warn "Config generation had issues." else     warn "Skipped (Python 3 not available)" fi  # ====== Summary ====== echo "" echo "========================================" echo "  Installation Complete!" echo "========================================" echo "" echo "  Verification checklist:" echo "  [ ] Docker + Reacher:  curl http://localhost:8080/health" echo "  [ ] Prospector:        npx prospector-mcp --help" echo "  [ ] mcp-whatsapp:      ls ~/mcp-whatsapp/bin/" echo "  [ ] MCP config:        cat ~/.codex/mcp.json" echo "" echo "  Next steps before first use:" echo "  1. Start WhatsApp: cd ~/mcp-whatsapp && ./bin/whatsapp-mcp serve" echo "  2. Scan QR:         open http://127.0.0.1:8765/pair" echo "  3. Snov.io Key:     get from https://app.snov.io > Account > API" echo "     Or run: $PYTHON ${SKILL_DIR}/scripts/generate_config.py --snovio-id YOUR_ID --snovio-secret YOUR_SECRET" echo "  4. Restart Codex" echo "" echo "  Bonus — No MCP mode (pure Python scripts):" echo "    export SNOVIO_CLIENT_ID=xxx" echo "    export SNOVIO_CLIENT_SECRET=xxx" echo "    $PYTHON ${SKILL_DIR}/scripts/snovio_api.py balance" echo "    $PYTHON ${SKILL_DIR}/scripts/verify_email_direct.py test@gmail.com" echo ""